import { useEffect, useRef } from "react";

// ── Underwater CONK logo (base64 encoded, circular crop) ──
const LOGO_SRC = "data:image/png;base64,";

interface Props {
  onConnect: () => Promise<void>;
}

// Detect in-app browsers (LinkedIn, Instagram, Facebook, Twitter) that block Google OAuth
function isWebView(): boolean {
  const ua = navigator.userAgent || ''
  return (
    /LinkedIn/i.test(ua) ||
    /FBAN|FBAV|FB_IAB/i.test(ua) ||
    /Instagram/i.test(ua) ||
    /Twitter/i.test(ua) ||
    /wv/.test(ua) ||
    (/iPhone|iPod|iPad/.test(ua) && !/Safari/.test(ua) && /AppleWebKit/.test(ua))
  )
}

function openInBrowser() {
  const url = window.location.href
  // iOS — try to open in Safari
  if (/iPhone|iPod|iPad/.test(navigator.userAgent)) {
    window.location.href = `x-safari-${url}`
    setTimeout(() => { window.location.href = url }, 500)
  } else {
    // Android — intent to open in Chrome
    window.location.href = `intent://${url.replace(/^https?:\/\//, '')}#Intent;scheme=https;package=com.android.chrome;end`
    setTimeout(() => { window.location.href = url }, 500)
  }
}

export function ConkHomeScreen({ onConnect }: Props) {
  // Block OAuth attempts in webviews — Google will reject them
  if (isWebView()) {
    return (
      <div style={{
        minHeight: '100dvh', background: '#000810',
        display: 'flex', flexDirection: 'column',
        alignItems: 'center', justifyContent: 'center',
        padding: '32px 24px', textAlign: 'center'
      }}>
        <div style={{fontSize: '40px', marginBottom: '20px'}}>🐚</div>
        <div style={{
          fontFamily: 'var(--font-mono)', fontSize: '18px',
          fontWeight: 700, color: '#00B8E6', marginBottom: '12px'
        }}>
          Open in your browser
        </div>
        <div style={{
          fontFamily: 'var(--font-mono)', fontSize: '12px',
          color: 'rgba(255,255,255,0.5)', lineHeight: 1.7,
          marginBottom: '28px', maxWidth: '280px'
        }}>
          CONK uses Google sign-in which requires a real browser.
          Tap below to open in Safari or Chrome.
        </div>
        <button
          onClick={openInBrowser}
          style={{
            padding: '14px 28px',
            background: 'rgba(0,184,230,0.1)',
            border: '1px solid rgba(0,184,230,0.4)',
            borderRadius: '8px',
            color: '#00B8E6',
            fontFamily: 'var(--font-mono)',
            fontSize: '13px',
            fontWeight: 600,
            cursor: 'pointer',
            marginBottom: '16px',
            width: '100%',
            maxWidth: '280px'
          }}>
          Open in Browser →
        </button>
        <div style={{
          fontFamily: 'var(--font-mono)', fontSize: '10px',
          color: 'rgba(255,255,255,0.3)'
        }}>
          conk.app · anonymous communication protocol
        </div>
      </div>
    )
  }
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animRef   = useRef<number>(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d")!;

    let W = 0, H = 0, cx = 0, cy = 0;
    const LCY = () => cy - 110;

    const resize = () => {
      W = canvas.width  = canvas.offsetWidth;
      H = canvas.height = canvas.offsetHeight;
      cx = W / 2; cy = H / 2;
    };
    resize();
    window.addEventListener("resize", resize);

    // ── Mouse ──────────────────────────────────────────────
    const mouse = { x: cx, y: cy };
    const onMove = (e: MouseEvent) => {
      const r = canvas.getBoundingClientRect();
      mouse.x = e.clientX - r.left;
      mouse.y = e.clientY - r.top;
    };
    window.addEventListener("mousemove", onMove);

    // ── Halo rings ─────────────────────────────────────────
    type Ring = { r: number; maxR: number; alpha: number; speed: number; thick: number };
    const rings: Ring[] = [];
    let haloTimer = 0;
    let haloNextAt = 2.0 + Math.random() * 1.5;
    const emitHalo = (big = false) => {
      rings.push({ r: 0, maxR: big ? 400 : 270, alpha: big ? 0.55 : 0.2, speed: big ? 2.8 : 1.5, thick: big ? 1.8 : 1.0 });
    };

    // ── Bubbles ────────────────────────────────────────────
    type Bubble = { x: number; y: number; r: number; speed: number; wobble: number; wobbleSpd: number; wobbleAmp: number; alpha: number; glowing: boolean };
    const NBUB = 60;
    const bubbles: Bubble[] = [];
    const mkBubble = (): Bubble => ({
      x: Math.random() * (W || 800),
      y: (H || 600) + 10 + Math.random() * 120,
      r: 2 + Math.random() * 11,
      speed: 0.3 + Math.random() * 0.85,
      wobble: Math.random() * Math.PI * 2,
      wobbleSpd: 0.018 + Math.random() * 0.038,
      wobbleAmp: 0.3 + Math.random() * 1.8,
      alpha: 0.1 + Math.random() * 0.22,
      glowing: false,
    });
    for (let i = 0; i < NBUB; i++) { const b = mkBubble(); b.y = Math.random() * ((H||600) + 100) - 50; bubbles.push(b); }

    // ── Sinking debris ─────────────────────────────────────
    type Sinker = { x: number; y: number; speed: number; drift: number; r: number; alpha: number; rotation: number; rotSpd: number; shape: string; size: number; parallax: number };
    const NSINK = 40;
    const sinkers: Sinker[] = [];
    const mkSinker = (): Sinker => ({
      x: Math.random() * (W || 800),
      y: -10 - Math.random() * 80,
      speed: 0.1 + Math.random() * 0.32,
      drift: (Math.random() - 0.5) * 0.18,
      r: 0.5 + Math.random() * 2.2,
      alpha: 0.05 + Math.random() * 0.14,
      rotation: Math.random() * Math.PI * 2,
      rotSpd: (Math.random() - 0.5) * 0.012,
      shape: Math.random() < 0.5 ? "dot" : "line",
      size: 1.5 + Math.random() * 3.5,
      parallax: 0.3 + Math.random() * 1.2,
    });
    for (let i = 0; i < NSINK; i++) { const s = mkSinker(); s.y = Math.random() * (H||600); sinkers.push(s); }

    // ── Caustics ───────────────────────────────────────────
    const caustics = Array.from({ length: 5 }, () => ({
      x: (Math.random() - 0.5) * 800 + 400,
      y: (Math.random() - 0.5) * 600 + 300,
      r: 20 + Math.random() * 48,
      phase: Math.random() * Math.PI * 2,
      speed: 0.007 + Math.random() * 0.011,
      alpha: 0.015 + Math.random() * 0.025,
      dx: (Math.random() - 0.5) * 0.09,
      dy: (Math.random() - 0.5) * 0.06,
    }));

    const drawBubble = (b: Bubble) => {
      const color = b.glowing ? `rgba(0,210,255,${b.alpha * 0.7})` : `rgba(80,190,235,${b.alpha * 0.5})`;
      ctx.beginPath(); ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.strokeStyle = color; ctx.lineWidth = 0.9; ctx.stroke();
      ctx.beginPath(); ctx.arc(b.x - b.r * 0.32, b.y - b.r * 0.3, b.r * 0.22, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(200,245,255,${b.alpha * 0.55})`; ctx.fill();
      ctx.beginPath(); ctx.arc(b.x + b.r * 0.2, b.y - b.r * 0.2, b.r * 0.1, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(200,240,255,${b.alpha * 0.3})`; ctx.fill();
      ctx.beginPath(); ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(0,100,170,${b.alpha * 0.06})`; ctx.fill();
    };

    let t = 0;
    ctx.fillStyle = "#000810"; ctx.fillRect(0, 0, 1200, 700);

    const draw = () => {
      resize();
      t += 0.012; haloTimer += 0.012;
      const lcy = LCY();

      // Background
      ctx.fillStyle = "rgba(0,8,16,0.22)"; ctx.fillRect(0, 0, W, H);

      // Dark vignette
      const vign = ctx.createRadialGradient(cx, lcy, 0, cx, lcy, Math.max(W, H) * 0.7);
      vign.addColorStop(0, "rgba(0,2,6,0.72)"); vign.addColorStop(0.18, "rgba(0,4,10,0.45)");
      vign.addColorStop(0.45, "rgba(0,6,14,0.15)"); vign.addColorStop(1, "rgba(0,8,16,0)");
      ctx.fillStyle = vign; ctx.fillRect(0, 0, W, H);

      // Purple corners
      [[0,0],[W,0],[0,H],[W,H]].forEach(([ex, ey]) => {
        const cg = ctx.createRadialGradient(ex, ey, 0, ex, ey, Math.min(W, H) * 0.55);
        cg.addColorStop(0, "rgba(55,0,100,0.12)"); cg.addColorStop(0.45, "rgba(30,0,60,0.06)"); cg.addColorStop(1, "rgba(0,0,0,0)");
        ctx.fillStyle = cg; ctx.fillRect(0, 0, W, H);
      });

      // Caustics
      caustics.forEach(ca => {
        ca.phase += ca.speed; ca.x += ca.dx; ca.y += ca.dy;
        if (ca.x < -60) ca.x = W + 60; if (ca.x > W + 60) ca.x = -60;
        if (ca.y < -60) ca.y = H + 60; if (ca.y > H + 60) ca.y = -60;
        const sc = 0.8 + Math.sin(ca.phase) * 0.22;
        const g = ctx.createRadialGradient(ca.x, ca.y, 0, ca.x, ca.y, ca.r * sc);
        g.addColorStop(0, `rgba(0,130,200,${ca.alpha})`); g.addColorStop(0.6, `rgba(0,60,140,${ca.alpha * 0.3})`); g.addColorStop(1, "rgba(0,8,16,0)");
        ctx.fillStyle = g; ctx.beginPath(); ctx.arc(ca.x, ca.y, ca.r * sc, 0, Math.PI * 2); ctx.fill();
      });

      // Sinkers
      sinkers.forEach((s, si) => {
        s.y += s.speed;
        s.x += s.drift + Math.sin(t * 0.38 + si * 0.3) * 0.07;
        s.x += (mouse.x - cx) * 0.00025 * s.parallax;
        s.y += (mouse.y - cy) * 0.00012 * s.parallax;
        s.rotation += s.rotSpd;
        const sdist = Math.hypot(cx - s.x, lcy - s.y);
        if (sdist > 125) {
          ctx.save(); ctx.translate(s.x, s.y); ctx.rotate(s.rotation); ctx.globalAlpha = s.alpha;
          ctx.fillStyle = "rgba(50,130,195,1)"; ctx.strokeStyle = "rgba(70,155,215,1)"; ctx.lineWidth = 0.5;
          if (s.shape === "dot") { ctx.beginPath(); ctx.arc(0, 0, s.r, 0, Math.PI * 2); ctx.fill(); }
          else { ctx.beginPath(); ctx.moveTo(-s.size, 0); ctx.lineTo(s.size, 0); ctx.stroke(); }
          ctx.globalAlpha = 1; ctx.restore();
        }
        if (s.y > H + 15) sinkers[si] = mkSinker();
      });

      // Bubbles
      bubbles.forEach((b, bi) => {
        b.wobble += b.wobbleSpd;
        const mdx = (mouse.x - cx) * 0.0006;
        b.x += Math.sin(b.wobble) * b.wobbleAmp + mdx * (b.r / 20);
        b.y -= b.speed;
        const ld = Math.hypot(cx - b.x, lcy - b.y);
        b.glowing = ld < 130;
        if (ld < 118) { b.y -= b.speed * 0.5; }
        else {
          if (ld < 150) ctx.globalAlpha = Math.max(0, (ld - 118) / 32);
          drawBubble(b);
          ctx.globalAlpha = 1;
        }
        if (b.y < -b.r * 2) bubbles[bi] = mkBubble();
      });

      // Logo ambient glow
      const pulse = 0.055 + Math.sin(t * 0.85) * 0.022;
      const logoGlow = ctx.createRadialGradient(cx, lcy, 32, cx, lcy, 195);
      logoGlow.addColorStop(0, `rgba(0,200,255,${pulse + 0.02})`);
      logoGlow.addColorStop(0.18, `rgba(0,160,230,${pulse * 0.7})`);
      logoGlow.addColorStop(0.45, `rgba(0,70,140,${pulse * 0.35})`);
      logoGlow.addColorStop(1, "rgba(0,8,16,0)");
      ctx.fillStyle = logoGlow; ctx.beginPath(); ctx.arc(cx, lcy, 195, 0, Math.PI * 2); ctx.fill();

      // Halo rings
      if (haloTimer > haloNextAt) {
        emitHalo(false); haloTimer = 0; haloNextAt = 1.8 + Math.random() * 1.7;
      }
      for (let i = rings.length - 1; i >= 0; i--) {
        const rg = rings[i]; rg.r += rg.speed;
        const fade = Math.pow(1 - rg.r / rg.maxR, 1.3);
        if (fade <= 0) { rings.splice(i, 1); continue; }
        ctx.beginPath(); ctx.arc(cx, lcy, rg.r, 0, Math.PI * 2);
        ctx.strokeStyle = `rgba(0,184,230,${rg.alpha * fade})`; ctx.lineWidth = rg.thick; ctx.stroke();
        if (rg.r > 25) {
          ctx.beginPath(); ctx.arc(cx, lcy, rg.r * 0.7, 0, Math.PI * 2);
          ctx.strokeStyle = `rgba(0,210,255,${rg.alpha * fade * 0.3})`; ctx.lineWidth = 0.5; ctx.stroke();
        }
      }

      // Re-darken center so logo pops
      const reDark = ctx.createRadialGradient(cx, lcy, 0, cx, lcy, 115);
      reDark.addColorStop(0, "rgba(0,2,6,0.58)"); reDark.addColorStop(0.38, "rgba(0,4,10,0.28)"); reDark.addColorStop(1, "rgba(0,8,16,0)");
      ctx.fillStyle = reDark; ctx.fillRect(0, 0, W, H);

      // Depth fade top
      const topFade = ctx.createLinearGradient(0, 0, 0, H * 0.22);
      topFade.addColorStop(0, "rgba(0,3,10,0.4)"); topFade.addColorStop(1, "rgba(0,8,16,0)");
      ctx.fillStyle = topFade; ctx.fillRect(0, 0, W, H * 0.22);

      animRef.current = requestAnimationFrame(draw);
    };

    animRef.current = requestAnimationFrame(draw);

    return () => {
      cancelAnimationFrame(animRef.current);
      window.removeEventListener("resize", resize);
      window.removeEventListener("mousemove", onMove);
    };
  }, []);

  return (
    <div style={{ position: "relative", width: "100%", height: "100vh", background: "#000810", overflow: "hidden" }}>
      <canvas
        ref={canvasRef}
        style={{ position: "absolute", inset: 0, width: "100%", height: "100%" }}
      />
      <div style={{
        position: "absolute", inset: 0,
        display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center",
        zIndex: 2, pointerEvents: "none",
      }}>
        {/* Logo */}
        <div
          style={{ position: "relative", marginBottom: 22, pointerEvents: "all", cursor: "pointer" }}
          onClick={() => {
            // Pulse handled in canvas via halo rings — no extra action needed
          }}
        >
          <img
            src={LOGO_SRC}
            alt="CONK"
            style={{
              width: 220, height: 220,
              objectFit: "contain",
              display: "block",
              borderRadius: "50%",
              position: "relative",
              zIndex: 2,
              filter: [
                "drop-shadow(0 0 24px rgba(0,200,255,0.85))",
                "drop-shadow(0 0 60px rgba(0,120,200,0.5))",
                "drop-shadow(0 0 120px rgba(0,160,230,0.22))",
              ].join(" "),
            }}
          />
        </div>

        {/* Tagline */}
        <p style={{
          fontFamily: "'Space Mono', 'Courier New', monospace",
          fontSize: 9.5, color: "rgba(0,184,230,0.5)",
          letterSpacing: "0.22em", textTransform: "uppercase",
          marginBottom: 34,
        }}>
          The protocol where agents communicate
        </p>

        {/* Google Login Button */}
        <button
          onClick={onConnect}
          style={{
            pointerEvents: "all",
            display: "flex", alignItems: "center", gap: 10,
            padding: "13px 30px",
            background: "rgba(0,5,12,0.85)",
            border: "1px solid rgba(0,184,230,0.38)",
            borderRadius: 3, cursor: "pointer",
            fontFamily: "'Space Mono', monospace",
            fontSize: 11, fontWeight: 700,
            color: "#00B8E6", letterSpacing: "0.12em",
          }}
        >
          <svg width="13" height="13" viewBox="0 0 24 24">
            <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
            <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
            <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
            <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
          </svg>
          ENTER THE TIDE
        </button>

        {/* Three Laws */}
        <div style={{ marginTop: 38, display: "flex", flexDirection: "column", gap: 6, alignItems: "center" }}>
          {[
            ["I.",   "Casts never reach the Harbor. Ever."],
            ["II.",  "Harbor knows only that balance decreased."],
            ["III.", "Vessel → Relay → Cast. Harbor sees none of it."],
          ].map(([num, text]) => (
            <div key={num} style={{ display: "flex", gap: 10, alignItems: "center", fontFamily: "'Space Mono', monospace" }}>
              <span style={{ fontSize: 8, color: "rgba(0,184,230,0.28)", minWidth: 18 }}>{num}</span>
              <span style={{ fontSize: 8, color: "rgba(255,255,255,0.14)", letterSpacing: "0.04em" }}>{text}</span>
            </div>
          ))}
        </div>

        {/* Footer */}
        <p style={{
          marginTop: 30,
          fontFamily: "'Space Mono', monospace",
          fontSize: 7, color: "rgba(255,255,255,0.06)",
          letterSpacing: "0.14em",
        }}>
          AXIOM TIDE LLC · CONK PROTOCOL · MAINNET · APRIL 2026
        </p>
      </div>
    </div>
  );
}
